if (! function_exists('data_frequency_table')) {
    function data_frequency_table($values, $sort_by = null, $max_entries = null, $include_cumulative = null)
    {
        if (!is_array($values) || empty($values)) {
            return json_encode(['error' => 'Non-empty array of values required', 'frequency_table' => []]);
        }
        $sortBy = isset($sort_by) ? $sort_by : 'frequency';
        $maxEntries = isset($max_entries) && $max_entries > 0 ? (int)$max_entries : 50;
        $includeCumul = isset($include_cumulative) ? (bool)$include_cumulative : true;

        $total = count($values);
        $freq = [];

        foreach ($values as $v) {
            // Convert to string for use as array key
            $key = is_bool($v) ? ($v ? 'true' : 'false') : (string)$v;
            if (!isset($freq[$key])) {
                $freq[$key] = ['value' => $v, 'original_type' => gettype($v), 'count' => 0];
            }
            $freq[$key]['count']++;
        }

        // Count unique values
        $uniqueCount = count($freq);

        // Convert to indexed array
        $table = array_values($freq);

        // Sort
        if ($sortBy === 'value') {
            usort($table, function($a, $b) {
                if (is_numeric($a['value']) && is_numeric($b['value'])) {
                    return $a['value'] - $b['value'];
                }
                return strcmp((string)$a['value'], (string)$b['value']);
            });
        } elseif ($sortBy === 'value_desc') {
            usort($table, function($a, $b) {
                if (is_numeric($a['value']) && is_numeric($b['value'])) {
                    return $b['value'] - $a['value'];
                }
                return strcmp((string)$b['value'], (string)$a['value']);
            });
        } else {
            // frequency descending (default)
            usort($table, function($a, $b) {
                if ($b['count'] !== $a['count']) return $b['count'] - $a['count'];
                return strcmp((string)$a['value'], (string)$b['value']);
            });
        }

        // Limit entries
        $table = array_slice($table, 0, $maxEntries);

        // Compute percentages
        $cumulative = 0;
        $entries = [];
        foreach ($table as &$row) {
            $pct = $total > 0 ? ($row['count'] / $total) * 100 : 0;
            $cumulative += $pct;
            $entry = [
                'value' => $row['value'],
                'type' => $row['original_type'],
                'count' => $row['count'],
                'percentage' => round($pct, 2),
            ];
            if ($includeCumul) {
                $entry['cumulative_percentage'] = round($cumulative, 2);
            }
            $entries[] = $entry;
        }

        // Compute mode (most frequent value)
        $mode = null;
        $maxCount = 0;
        foreach ($freq as $f) {
            if ($f['count'] > $maxCount) {
                $maxCount = $f['count'];
                $mode = $f['value'];
            }
        }

        // Entropy
        $entropy = 0;
        foreach ($freq as $f) {
            $p = $f['count'] / $total;
            if ($p > 0) {
                $entropy -= $p * log($p) / log(2);
            }
        }

        return json_encode([
            'total_values' => $total,
            'unique_values' => $uniqueCount,
            'mode' => $mode,
            'mode_frequency' => $maxCount,
            'mode_percentage' => round($maxCount / $total * 100, 2),
            'entropy_bits' => round($entropy, 4),
            'sort_order' => $sortBy,
            'entries_shown' => count($entries),
            'truncated' => $uniqueCount > $maxEntries,
            'frequency_table' => $entries,
            'next_steps' => [
                "Feed results to data_bin_sorter for grouped analysis.",
                "Pass mode/entropy to math_statistics for summary.",
                "Visualize counts via data_heatmap or data_to_emoji_art.",
            ],
        ]);
    }
